from azure.ai.projects.models import AgentStreamEvent, MessageDeltaChunk

# Streaming alternative — no polling needed
with client.agents.create_stream(thread_id=thread.id, agent_id=agent.id) as stream:
    for event_type, event_data, _ in stream:
        if event_type == AgentStreamEvent.THREAD_MESSAGE_DELTA:
            delta: MessageDeltaChunk = event_data
            for block in delta.delta.content:
                if hasattr(block, "text"):
                    print(block.text.value, end="", flush=True)
        elif event_type == AgentStreamEvent.THREAD_RUN_REQUIRES_ACTION:
            tool_outputs = execute_function_calls(
                event_data.required_action.submit_tool_outputs.tool_calls
            )
            stream.submit_tool_outputs(tool_outputs)

import json
from azure.ai.projects.models import FunctionTool

# Define the function schema (JSON Schema)
def get_weather(location: str, unit: str = "celsius") -> str:
    """Fetch weather — called by the agent runtime."""
    # In production: call a real weather API
    return json.dumps({"location": location, "temperature": 22, "unit": unit, "condition": "sunny"})

def get_stock_price(ticker: str) -> str:
    return json.dumps({"ticker": ticker, "price": 183.42, "currency": "USD"})

# Register functions with the agent
functions = FunctionTool(functions=[get_weather, get_stock_price])

agent = client.agents.create_agent(
    model="gpt-4o",
    name="financial-assistant",
    instructions="You help with weather and stock price queries.",
    tools=functions.definitions,   # JSON schemas derived from function signatures
)

# In the run loop, handle REQUIRES_ACTION by routing to the real function:
def execute_function_calls(tool_calls) -> list[dict]:
    outputs = []
    for call in tool_calls:
        fn_name   = call.function.name
        fn_args   = json.loads(call.function.arguments)

        if fn_name == "get_weather":
            result = get_weather(**fn_args)
        elif fn_name == "get_stock_price":
            result = get_stock_price(**fn_args)
        else:
            result = json.dumps({"error": f"Unknown function: {fn_name}"})

        outputs.append({"tool_call_id": call.id, "output": result})
    return outputs

# Run Steps expose the agent's intermediate reasoning —
# which tools it decided to call, and what it received back.

import time

run = client.agents.create_run(thread_id=thread.id, agent_id=agent.id)
while run.status not in ("completed", "failed", "cancelled", "expired"):
    time.sleep(1)
    run = client.agents.get_run(thread_id=thread.id, run_id=run.id)

# List all steps taken during this run
steps = client.agents.list_run_steps(thread_id=thread.id, run_id=run.id)
for step in steps.data:
    print(f"Step type: {step.type}, Status: {step.status}")
    if step.type == "tool_calls":
        for call in step.step_details.tool_calls:
            print(f"  Tool: {call.type}")
            if hasattr(call, "function"):
                print(f"    Function: {call.function.name}")
                print(f"    Arguments: {call.function.arguments}")
                print(f"    Output: {call.function.output}")
            elif hasattr(call, "code_interpreter"):
                print(f"    Code: {call.code_interpreter.input[:200]}")
